const data = $json.body.data.properties;

// 📌 공통 파라미터 (수업 리포트용)
const reportParams = {
  url_day: $json.body.data.id,
  학생이름: data["학생이름(S)"].formula.string,
  수업날짜: data["수업일시(S)"].formula.string,
  요일: data["요일"].formula.string,
  수업회차: data["수업회차(S)"].formula.string,
  과정: data["과정(S)"].formula.string,
  수업내용: data["진도/수업 내용"].rollup.array[0]?.rich_text[0]?.plain_text || ""
};

// 📌 수신자 배열 구성 (수업 리포트)
const reportRecipientList = [];

if (data["학부모연락처 1(S)"].formula.string) {
  reportRecipientList.push({
    recipientNo: data["학부모연락처 1(S)"].formula.string,
    templateParameter: reportParams
  });
}

if (data["학부모연락처 2(S)"].formula.string) {
  reportRecipientList.push({
    recipientNo: data["학부모연락처 2(S)"].formula.string,
    templateParameter: reportParams
  });
}

// 📌 [개선] 노션의 모든 타입에서 숫자를 안전하게 뽑아내는 만능 함수
function extractNumber(val) {
  if (val === null || val === undefined) return null;

  let targetValue;

  // 1. 노션 프로퍼티 오브젝트인 경우 처리
  if (typeof val === 'object') {
    // 수식(Formula)인 경우
    if (val.formula) {
      targetValue = val.formula.string !== undefined ? val.formula.string : val.formula.number;
    } 
    // 롤업(Rollup)인 경우
    else if (val.rollup && val.rollup.array) {
      const firstItem = val.rollup.array[0];
      if (firstItem && firstItem.select) targetValue = firstItem.select.name;
      else if (firstItem && firstItem.number !== undefined) targetValue = firstItem.number;
      else if (firstItem && firstItem.rich_text) targetValue = firstItem.rich_text[0]?.plain_text;
    }
  } 
  // 2. 이미 문자열이나 숫자인 경우
  else {
    targetValue = val;
  }

  if (targetValue === null || targetValue === undefined) return null;

  // 숫자가 아닌 글자가 섞여 있어도 숫자만 추출 (예: "4회차" -> 4)
  const match = String(targetValue).match(/\d+/);
  return match ? parseInt(match[0], 10) : null;
}

// 📌 [수정된 호출 부분] - 통째로 전달해야 함
const numFromSession = extractNumber(data["수업회차(S)"]);
const numFromCourse = extractNumber(data["수업구분"]); // 이제 Rollup도 인식함

// 📌 조건 판단
const sendPaymentNotice = (numFromSession !== null && numFromCourse !== null && numFromSession === numFromCourse);

// 📌 수정된 수업료 납부 알림용 파라미터
const paymentParams = {
  // 아래 항목들은 데이터가 있을 때만 값이 할당됨 (없으면 undefined)
  이름: data["학생이름(S)"]?.formula?.string,
  수업구분: data['수업구분']?.rollup?.array[0]?.select?.name,
  수업일시: data["수업일시(S)"]?.formula?.string,
  요일: data["요일"]?.formula?.string,
  다음수업일: data["다음수업일M"]?.formula?.string,

  // 📌 기타사항: 데이터가 없어도 빈 문자열("")을 넣어서 발송 보장
  기타안내: data["기타안내"]?.formula?.string || ""
};

// 📌 수신자 배열 구성 (수업료 납부 알림)
const paymentRecipientList = [];

if (data["학부모연락처 1(S)"].formula.string) {
  paymentRecipientList.push({
    recipientNo: data["학부모연락처 1(S)"].formula.string,
    templateParameter: paymentParams
  });
}

if (data["학부모연락처 2(S)"].formula.string) {
  paymentRecipientList.push({
    recipientNo: data["학부모연락처 2(S)"].formula.string,
    templateParameter: paymentParams
  });
}

return [{
  json: {
    // 수업 리포트 발송 데이터(사용자설정 senderKey,templateCode-NHNCloud)
    reportData: {
      senderKey: "7780249050d98477b04a1b589e4794c8ac1f7a78",
      templateCode: "Math4U-edu-2025002",
      recipientList: reportRecipientList
    },
    // 수업료 납부 알림 발송 데이터(사용자설정 senderKey,templateCode)
    paymentData: {
      senderKey: "7780249050d98477b04a1b589e4794c8ac1f7a78",
      templateCode: "Math4U-edu-2025004",
      recipientList: paymentRecipientList
    },
    // 조건 판단 플래그
    sendPaymentNotice: sendPaymentNotice,
    // Notion 업데이트용 ID
    notionPageId: $json.body.data.id
  }
}];

